"""
Demo app and tests for RateLimitMiddleware.

Shows how to add rate limiting to a FastAPI application and verifies the
expected behaviour: headers on all responses, 429 when burst is exhausted,
per-IP state shared across endpoints, and WebSocket passthrough.
"""

import pytest
from fastapi import FastAPI, WebSocket
from fastapi.testclient import TestClient

from fastapi.middleware.rate_limit import RateLimitMiddleware


# ---------------------------------------------------------------------------
# App factory
# ---------------------------------------------------------------------------


def make_app(requests_per_minute: int = 60, burst_size: int = 5) -> FastAPI:
    """Create a FastAPI app with RateLimitMiddleware configured."""
    app = FastAPI()
    app.add_middleware(
        RateLimitMiddleware,
        requests_per_minute=requests_per_minute,
        burst_size=burst_size,
    )

    @app.get("/")
    async def root() -> dict:
        return {"message": "hello"}

    @app.get("/health")
    async def health() -> dict:
        return {"status": "ok"}

    @app.websocket("/ws")
    async def ws_endpoint(websocket: WebSocket) -> None:
        await websocket.accept()
        await websocket.send_text("hello")
        await websocket.close()

    return app


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------


@pytest.fixture()
def client() -> TestClient:
    """TestClient with default config: 60 rpm, burst of 5."""
    return TestClient(make_app(requests_per_minute=60, burst_size=5))


# ---------------------------------------------------------------------------
# Normal requests (under the burst limit)
# ---------------------------------------------------------------------------


class TestNormalRequests:
    def test_request_under_limit_returns_200(self, client: TestClient) -> None:
        response = client.get("/")
        assert response.status_code == 200

    def test_response_body_is_correct(self, client: TestClient) -> None:
        response = client.get("/")
        assert response.json() == {"message": "hello"}

    def test_x_ratelimit_limit_header_present(self, client: TestClient) -> None:
        response = client.get("/")
        assert "X-RateLimit-Limit" in response.headers

    def test_x_ratelimit_limit_equals_configured_rpm(self, client: TestClient) -> None:
        response = client.get("/")
        assert response.headers["X-RateLimit-Limit"] == "60"

    def test_x_ratelimit_remaining_header_present(self, client: TestClient) -> None:
        response = client.get("/")
        assert "X-RateLimit-Remaining" in response.headers

    def test_x_ratelimit_remaining_is_non_negative_integer(
        self, client: TestClient
    ) -> None:
        response = client.get("/")
        remaining = int(response.headers["X-RateLimit-Remaining"])
        assert remaining >= 0

    def test_x_ratelimit_reset_header_present(self, client: TestClient) -> None:
        response = client.get("/")
        assert "X-RateLimit-Reset" in response.headers

    def test_x_ratelimit_reset_is_non_negative_integer(
        self, client: TestClient
    ) -> None:
        response = client.get("/")
        reset = int(response.headers["X-RateLimit-Reset"])
        assert reset >= 0

    def test_remaining_decreases_per_request(self, client: TestClient) -> None:
        r1 = client.get("/")
        r2 = client.get("/")
        remaining1 = int(r1.headers["X-RateLimit-Remaining"])
        remaining2 = int(r2.headers["X-RateLimit-Remaining"])
        assert remaining2 < remaining1

    def test_burst_size_requests_all_succeed(self, client: TestClient) -> None:
        for _ in range(5):
            response = client.get("/")
            assert response.status_code == 200


# ---------------------------------------------------------------------------
# Rate limit exceeded (burst exhausted)
# ---------------------------------------------------------------------------


class TestRateLimitExceeded:
    def test_returns_429_after_burst_exhausted(self, client: TestClient) -> None:
        for _ in range(5):
            client.get("/")
        response = client.get("/")
        assert response.status_code == 429

    def test_429_body_has_detail_field(self, client: TestClient) -> None:
        for _ in range(5):
            client.get("/")
        body = client.get("/").json()
        assert "detail" in body
        assert "Rate limit exceeded" in body["detail"]

    def test_429_body_has_retry_after_field(self, client: TestClient) -> None:
        for _ in range(5):
            client.get("/")
        body = client.get("/").json()
        assert "retry_after" in body

    def test_429_retry_after_is_positive_number(self, client: TestClient) -> None:
        for _ in range(5):
            client.get("/")
        body = client.get("/").json()
        assert isinstance(body["retry_after"], (int, float))
        assert body["retry_after"] > 0

    def test_429_has_x_ratelimit_limit_header(self, client: TestClient) -> None:
        for _ in range(5):
            client.get("/")
        response = client.get("/")
        assert "X-RateLimit-Limit" in response.headers

    def test_429_has_x_ratelimit_remaining_header(self, client: TestClient) -> None:
        for _ in range(5):
            client.get("/")
        response = client.get("/")
        assert "X-RateLimit-Remaining" in response.headers

    def test_429_has_x_ratelimit_reset_header(self, client: TestClient) -> None:
        for _ in range(5):
            client.get("/")
        response = client.get("/")
        assert "X-RateLimit-Reset" in response.headers

    def test_429_x_ratelimit_remaining_is_zero(self, client: TestClient) -> None:
        for _ in range(5):
            client.get("/")
        response = client.get("/")
        assert response.headers["X-RateLimit-Remaining"] == "0"


# ---------------------------------------------------------------------------
# Per-IP rate limiting
# ---------------------------------------------------------------------------


class TestPerClientRateLimit:
    def test_rate_limit_shared_across_endpoints(self, client: TestClient) -> None:
        """Requests to different paths share the same per-IP token bucket."""
        for _ in range(3):
            client.get("/")
        for _ in range(2):
            client.get("/health")
        # 5 total requests have consumed the burst
        response = client.get("/")
        assert response.status_code == 429

    def test_custom_burst_size_respected(self) -> None:
        c = TestClient(make_app(requests_per_minute=120, burst_size=2))
        assert c.get("/").status_code == 200
        assert c.get("/").status_code == 200
        assert c.get("/").status_code == 429

    def test_custom_rpm_reflected_in_limit_header(self) -> None:
        c = TestClient(make_app(requests_per_minute=30, burst_size=3))
        response = c.get("/")
        assert response.headers["X-RateLimit-Limit"] == "30"


# ---------------------------------------------------------------------------
# Non-HTTP scope (WebSocket) passthrough
# ---------------------------------------------------------------------------


class TestWebSocketPassthrough:
    def test_websocket_not_rate_limited(self) -> None:
        """WebSocket connections (non-HTTP scope) bypass the rate limiter."""
        app = make_app(requests_per_minute=60, burst_size=1)
        c = TestClient(app)
        # Exhaust the single-token burst via HTTP
        c.get("/")
        # WebSocket should still connect and exchange messages
        with c.websocket_connect("/ws") as ws:
            data = ws.receive_text()
            assert data == "hello"

